/* Aula 39 — modelJs: render lento vs rápido */

const lentoBtn = document.querySelector('#lento');
const rapidoBtn = document.querySelector('#rapido');
const lista = document.querySelector('#lista');

const dados = Array.from({ length: 2000 }, (_, i) => `Item ${i}`);

function limpar() {
  if (lista) lista.innerHTML = '';
}

function renderLento() {
  if (!lista) return;
  limpar();

  console.time('renderLento');
  for (const txt of dados) {
    // pior padrão: mexe no innerHTML em loop
    lista.innerHTML += `<li>${txt}</li>`;
  }
  console.timeEnd('renderLento');
}

function renderRapido() {
  if (!lista) return;
  limpar();

  console.time('renderRapido');
  const frag = document.createDocumentFragment();
  for (const txt of dados) {
    const li = document.createElement('li');
    li.textContent = txt;
    frag.appendChild(li);
  }
  lista.appendChild(frag);
  console.timeEnd('renderRapido');
}

if (lentoBtn) lentoBtn.addEventListener('click', renderLento);
if (rapidoBtn) rapidoBtn.addEventListener('click', renderRapido);
